// HTTP Request splits JSON arrays — use $input.all() to collect every incident
const items = $input.all();
const incidents = items.length > 0 && Array.isArray(items[0].json)
  ? items[0].json
  : items.map(function(i){ return i.json; }).filter(function(i){ return i && i.incident_id; });
const now = Date.now();
const SLA = { CRITICAL: 30, HIGH: 120, MEDIUM: 480, LOW: 1440 };
const breached = [];
const warning = [];
for (const inc of incidents) {
  const created = new Date(inc.created_at).getTime();
  const ageMin = (now - created) / 60000;
  const sev = inc.severity || 'LOW';
  const slaMin = SLA[sev] || SLA.LOW;
  const pct = (ageMin / slaMin) * 100;
  if (pct >= 100) breached.push({ ...inc, age_minutes: Math.round(ageMin), sla_minutes: slaMin, pct: Math.round(pct) });
  else if (pct >= 80) warning.push({ ...inc, age_minutes: Math.round(ageMin), sla_minutes: slaMin, pct: Math.round(pct) });
}
return [{ json: { breached, warning, total_open: incidents.length, checked_at: new Date().toISOString() } }];

const data = $input.first().json;
const breached = data.breached || [];
const warning = data.warning || [];
const severityEmoji = { CRITICAL: ':rotating_light:', HIGH: ':red_circle:', MEDIUM: ':large_yellow_circle:', LOW: ':white_circle:' };
const buildSection = function(list, label, emoji) {
  if (list.length === 0) return [];
  const lines = list.slice(0, 10).map(function(inc) {
    const e = severityEmoji[inc.severity] || ':white_circle:';
    const id = (inc.incident_id || inc.id || 'unknown').slice(0, 8);
    const src = (inc.affected_ips && inc.affected_ips[0]) || 'N/A';
    const threat = inc.threat_type || inc.type || inc.title || 'Unknown';
    return e + ' *' + id + '* \u2014 ' + threat + ' | ' + src + ' | Age: ' + inc.age_minutes + 'm / SLA: ' + inc.sla_minutes + 'm (' + inc.pct + '%)';
  }).join('\n');
  return [
    { type: 'section', text: { type: 'mrkdwn', text: '*' + emoji + ' ' + label + ' (' + list.length + ')*' } },
    { type: 'section', text: { type: 'mrkdwn', text: lines } }
  ];
};
const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':hourglass_flowing_sand: SLA Watchdog Report', emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: '*Open Incidents:* ' + data.total_open + ' | *Checked:* ' + data.checked_at } },
  { type: 'divider' },
  ...buildSection(breached, 'SLA BREACHED', ':fire:'),
  ...buildSection(warning, 'SLA WARNING (>80%)', ':warning:'),
  { type: 'divider' },
  { type: 'context', elements: [{ type: 'mrkdwn', text: 'CyberSentinel AI \u00B7 SLA Watchdog \u00B7 Runs every 15 min' }] }
];
return [{ json: { channel: 'C0ANVSMJTH9', text: 'SLA Alert: ' + breached.length + ' breached, ' + warning.length + ' warning', blocks } }];

const d = $input.first().json;
const slaData = $('Check SLA Thresholds').item.json;
const reportId = 'sla-' + Date.now().toString(36);
return [{ json: { report_id: reportId, workflow: 'sla_watchdog', title: 'SLA Alert — ' + (slaData.breached||[]).length + ' breached, ' + (slaData.warning||[]).length + ' warning (' + new Date().toLocaleTimeString() + ')', slack_payload: d } }];
